1	// game-of-life.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { nextGeneration } from "./game-of-life.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("should return an empty array for an empty grid", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("should let a single cell die (underpopulation, 0 neighbors)", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("should let two neighboring cells die (underpopulation, 1 neighbor each)", () => {
13	    expect(
14	      nextGeneration([
15	        [0, 1],
16	        [1, 1],
17	      ])
18	    ).toEqual([]);
19	  });
20	  it("should keep a live cell with 3 live neighbors alive (survival)", () => {
21	    // ###   <- (0,0), (1,0), (2,0)
22	    // .#.   <- (1,1) has exactly 3 live neighbors -> survives
23	    const nextGen = nextGeneration([
24	      [0, 0],
25	      [1, 0],
26	      [2, 0],
27	      [1, 1],
28	    ]);
29	    expect(nextGen).toContainEqual([1, 1]);
30	  });
31	  it("should let a live cell with 4 live neighbors die (overpopulation)", () => {
32	    // ###   <- (0,0), (1,0), (2,0)
33	    // .#.   <- (1,1) has 4 live neighbors -> dies
34	    // ###   <- (0,2), (1,2), (2,2)
35	    const nextGen = nextGeneration([
36	      [0, 0],
37	      [1, 0],
38	      [2, 0],
39	      [1, 1],
40	      [0, 2],
41	      [1, 2],
42	      [2, 2],
43	    ]);
44	    expect(nextGen).not.toContainEqual([1, 1]);
45	  });
46	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
47	    // ##.   <- (0,0), (1,0)
48	    // #..   <- (0,1); dead cell (1,1) has exactly 3 live neighbors -> comes to life
49	    const nextGen = nextGeneration([
50	      [0, 0],
51	      [1, 0],
52	      [0, 1],
53	    ]);
54	    expect(nextGen).toContainEqual([1, 1]);
55	  });
56	  it("should keep a block still life unchanged", () => {
57	    // ##   <- (0,0), (1,0)
58	    // ##   <- (0,1), (1,1); every cell has exactly 3 neighbors -> block stays
59	    const nextGen = nextGeneration([
60	      [0, 0],
61	      [1, 0],
62	      [0, 1],
63	      [1, 1],
64	    ]);
65	    expect(nextGen).toHaveLength(4);
66	    expect(nextGen).toEqual(
67	      expect.arrayContaining([
68	        [0, 0],
69	        [1, 0],
70	        [0, 1],
71	        [1, 1],
72	      ])
73	    );
74	  });
75	  it.todo(
76	    "should oscillate a vertical blinker to a horizontal blinker (negative coordinates)"
77	  );
78	});
