const candidates = (liveCells: Cell[]): Cell[] => {
  const all = liveCells.flatMap((cell) => [cell, ...neighborsOf(cell)]);
  return all.filter(
    ([x, y], index) =>
      all.findIndex(([otherX, otherY]) => otherX === x && otherY === y) ===
      index
  );
};
